// POSIX Paylasilan Bellek - Uretici (Producer)
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <sys/shm.h>
#include <sys/stat.h>

int main() {
    const int SIZE = 4096;
    const char *name = "OS";
    int shm_fd;
    void *ptr;

    /* paylasilan bellek nesnesi olustur */
    shm_fd = shm_open(name, O_CREAT | O_RDWR, 0666);
    ftruncate(shm_fd, SIZE);

    /* bellek esleme */
    ptr = mmap(0, SIZE, PROT_WRITE, MAP_SHARED, shm_fd, 0);

    /* paylasilan bellege yaz */
    sprintf(ptr, "%s", "Hello");
    ptr += strlen("Hello");
    sprintf(ptr, "%s", "World!");

    return 0;
}

// POSIX Paylasilan Bellek - Tuketici (Consumer)
int main() {
    const int SIZE = 4096;
    const char *name = "OS";
    int shm_fd;
    void *ptr;

    /* paylasilan bellek nesnesini ac */
    shm_fd = shm_open(name, O_RDONLY, 0666);
    ptr = mmap(0, SIZE, PROT_READ, MAP_SHARED, shm_fd, 0);

    /* paylasilan bellekten oku */
    printf("%s", (char *)ptr);

    /* paylasilan bellek nesnesini sil */
    shm_unlink(name);

    return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>

int main(void) {
    int fd[2], nbytes;
    pid_t childpid;
    char string[] = "Hello, world!\n";
    char readbuffer[80];

    pipe(fd);  /* boru olustur */

    if((childpid = fork()) == -1) {
        perror("fork");
        exit(1);
    }

    if(childpid == 0) {
        /* Cocuk: borunun giris tarafini kapat */
        close(fd[0]);
        /* Cikis tarafindan yaz */
        write(fd[1], string, (strlen(string)+1));
        exit(0);
    }
    else {
        /* Ebeveyn: borunun cikis tarafini kapat */
        close(fd[1]);
        /* Giris tarafindan oku */
        nbytes = read(fd[0], readbuffer, sizeof(readbuffer));
        printf("Received string: %s", readbuffer);
    }

    return(0);
}

